proof fn phi_neg_5_same_addr_single(pre: Slab, post: Slab, result: Result<*mut u8, Error>)
    requires
        pre.inv(),
    ensures
        post.inv(),
            match result {
                Ok(ptr) => {
                    let addr = ptr as usize;
                    &&& pre@.free_addrs.contains(addr)
                    &&& addr % post@.block_size == 0
                    &&& post@ == SlabView {
                        allocated_addrs: pre@.allocated_addrs.insert(addr),
                        free_addrs: pre@.free_addrs.remove(addr),
                        ..pre@
                    }
                },
                Err(_) => {
                    &&& pre@.free_addrs == Set::<usize>::empty()
                    &&& post@ == pre@
                },
            },
{
    // --- Concrete input (pre-state with only one free block) ---
assume(pre@.block_size == 64);
assume(pre@.start_addr == 0x1000);
assume(pre@.end_addr == 0x2000);
assume(pre@.free_addrs == Set::<usize>::empty().insert(0x1000usize));
assume(pre@.allocated_addrs == Set::<usize>::empty());

// --- Concrete output (trivially the only choice) ---
assume(result is Ok);
let ptr = result.unwrap();
assume(ptr as usize == 0x1000);
assume(post@.block_size == 64);
assume(post@.start_addr == 0x1000);
assume(post@.end_addr == 0x2000);
assume(post@.allocated_addrs == Set::<usize>::empty().insert(0x1000usize));
assume(post@.free_addrs == Set::<usize>::empty());
}

